INSERT INTO rms_blog_post (author_id, title, content, excerpt, slug, status, featured_image, og_image, tags, meta_title, meta_description, meta_keywords, canonical_url, schema_json, reading_time, is_featured, published_at, date_added, date_modified) VALUES
(1, 'Como montar um Design System escalável no e-commerce', '<p>Mapeie cores, tipografia e espaçamentos em tokens; crie biblioteca de componentes versionada; documente guidelines no Storybook; integre lint de tokens na pipeline.</p><p>Use nomenclatura semântica, evite hardcode, e conecte o Figma a tokens JSON exportados para o front. Planeje governança: quem aprova, como versionar e como deprecar.</p>', 'Tokens, componentes e governança para manter consistência.', 'design-system-escalavel-ecommerce', 'published', '', '', 'design system,figma,tokens,governanca', 'Design System escalável no e-commerce', 'Guia prático para estruturar tokens, biblioteca e governança.', 'design system, tokens, figma', '', '', 6, 1, NOW(), NOW(), NOW()),
(1, 'Core Web Vitals 2026: checklist rápido de performance', '<p>Priorize LCP: preload da hero image, compressão WebP/AVIF, font-display swap e server-side render.</p><p>Para INP, reduza JS não essencial, use hydration parcial e delegue eventos. Monitore CLS com placeholders fixos e lazy loading nativo.</p>', 'Checklist enxuto para LCP, INP e CLS.', 'core-web-vitals-2026-checklist', 'published', '', '', 'performance,core web vitals,seo,lighthouse', 'Core Web Vitals 2026: checklist rápido', 'Passo a passo para melhorar LCP, INP e CLS no front.', 'performance, seo, vitals', '', '', 5, 1, NOW(), NOW(), NOW()),
(1, 'CI/CD para assets gráficos e front-end', '<p>Automatize builds de estilos e ícones com pipelines: lint, testes visuais, build, upload em CDN e invalidação de cache.</p><p>Use trunk-based, feature flags e ambientes de preview. Armazene artefatos versionados para rollbacks rápidos.</p>', 'Pipeline para gráficos, ícones e front.', 'ci-cd-assets-frontend', 'published', '', '', 'ci/cd,devops,assets,frontend', 'CI/CD para assets gráficos e front-end', 'Pipeline com lint, testes visuais e deploy em CDN.', 'ci/cd, devops, frontend', '', '', 5, 0, NOW(), NOW(), NOW()),
(1, 'Automatizando variações de peças gráficas com scripts', '<p>Use ferramentas de batch (ImageMagick/Sharp) para gerar formatos e tamanhos. Combine com templates em Figma/PSD exportados via API.</p><p>Inclua verificação automática de proporção, área segura e compressão. Publique artefatos direto em CDN.</p>', 'Scripts para gerar variações sem dor.', 'automacao-pecas-graficas', 'published', '', '', 'automacao,design,imagens,scripts', 'Automatizando variações de peças gráficas', 'Como gerar lotes de criativos com scripts e checagens.', 'automacao, design, imagens', '', '', 4, 0, NOW(), NOW(), NOW());
